def sd(s, prefix):
    return s[len(prefix) :] if s.startswith(prefix) else s


def latin(s):
    t = re.sub(r"\$\{[^}]+\}", "", s)
    t = re.sub(r"\$[a-zA-Z_][a-zA-Z0-9_]*", "", t)
    return bool(re.search(r"[A-Za-z]", t))


def validate(name, arr):
    assert len(arr) == 15, f"{name}: {len(arr)} strings"
    for i, s in enumerate(arr):
        if latin(s):
            raise ValueError(f"{name}[{i}] Latin: {s[:150]!r}")


def write_json(name, arr):
    validate(name, arr)
    (H / name).write_text(json.dumps({"he": arr}, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    print(f"OK {name}")


